import { createHash } from "node:crypto";
import { mkdir, readFile, readdir, writeFile } from "node:fs/promises";
import path from "node:path";

import { createDeterministicTar } from "./release-bundle.js";

const RELEASE_VERSION = "0.2.0";
const TEXT_EXTENSIONS = new Set([".js", ".json", ".md", ".sql", ".yaml", ".yml", ".ps1", ".sh"]);
const STATIC_FILES = ["package.json", "package-lock.json"];
const TREES = ["src", "verifier", "migrations", "diagnostic-migrations", "docs", "runtime"];
const PACKAGE_TREE = "packages/n8n-operational-package";
const PACKAGE_EXCLUSIONS = new Set(["packages/n8n-operational-package/compose.customer.yaml"]);
const RELEASE_FILES = {
  "release/v0.2.0/Dockerfile": "Dockerfile",
  "Dockerfile.verifier": "Dockerfile.verifier",
  "release/v0.2.0/compose.yaml": "compose.yaml",
  "release/v0.2.0/install-local.ps1": "install-local.ps1",
  "release/v0.2.0/install-local.sh": "install-local.sh",
  "release/v0.2.0/release-spec.json": "release-spec.json",
  "release/v0.2.0/OPERATOR.md": "OPERATOR.md"
};

export function releaseDigest(bytes) {
  return `sha256:${createHash("sha256").update(bytes).digest("hex")}`;
}

function normalizedBytes(file, bytes) {
  return TEXT_EXTENSIONS.has(path.extname(file).toLowerCase())
    ? Buffer.from(bytes.toString("utf8").replace(/\r\n/g, "\n"), "utf8") : bytes;
}

async function treeFiles(root, relative) {
  const directory = path.join(root, relative);
  const entries = await readdir(directory, { withFileTypes: true });
  const files = [];
  for (const entry of entries.sort((left, right) => left.name.localeCompare(right.name))) {
    const child = path.posix.join(relative.replaceAll("\\", "/"), entry.name);
    if (entry.isDirectory()) files.push(...await treeFiles(root, child));
    else if (entry.isFile()) files.push(child);
    else throw new Error(`Release input cannot contain links or special files: ${child}`);
  }
  return files;
}

export async function collectV02ReleaseEntries(root) {
  const mappings = STATIC_FILES.map((file) => [file, file]);
  for (const tree of TREES) {
    for (const file of await treeFiles(root, tree)) mappings.push([file, file]);
  }
  for (const file of await treeFiles(root, PACKAGE_TREE)) {
    if (!PACKAGE_EXCLUSIONS.has(file)) mappings.push([file, file]);
  }
  mappings.push(...Object.entries(RELEASE_FILES));
  const entries = [];
  for (const [source, target] of mappings) {
    const bytes = normalizedBytes(source, await readFile(path.join(root, source)));
    entries.push({ path: target.replaceAll("\\", "/"), bytes,
      mode: target.endsWith(".sh") ? 0o755 : 0o644 });
  }
  return entries.sort((left, right) => left.path.localeCompare(right.path));
}

function composeServiceBlock(compose, name, nextName) {
  const end = nextName ? `\n  ${nextName}:\n` : "\nvolumes:\n";
  return compose.match(new RegExp(`\\n  ${name}:\\n([\\s\\S]*?)${end}`))?.[1] ?? "";
}

export function validateV02ReleaseEntries(entries) {
  const issues = [];
  const paths = new Set(entries.map((entry) => entry.path));
  const forbidden = [...paths].filter((entry) => /(^|\/)(\.scratch|test|proof|node_modules|CONTEXT\.md)(\/|$)/i.test(entry)
    || /(^|\/)(\.env(?:\.|$)|[^/]+\.(?:db|sqlite|pem|key))$/i.test(entry));
  for (const file of forbidden) issues.push({ code: "FORBIDDEN_RELEASE_PATH", path: file });
  for (const entry of entries) {
    const text = entry.bytes.toString("utf8");
    if (/ed25519-pkcs8:[A-Za-z0-9+/]{40,}|-----BEGIN (?:RSA |EC |OPENSSH )?PRIVATE KEY-----\r?\n[A-Za-z0-9+/=]{32}|local-development-bootstrap-token/i.test(text)) {
      issues.push({ code: "SECRET_MATERIAL_INCLUDED", path: entry.path });
    }
    if (/\b(?:AWS_ACCESS_KEY_ID|AWS_SECRET_ACCESS_KEY|OPENAI_API_KEY|ANTHROPIC_API_KEY)\b/.test(text)) {
      issues.push({ code: "PROVIDER_CREDENTIAL_REQUIREMENT", path: entry.path });
    }
    if (/N8N_ADAPTER_TEST_CONTROLS_ENABLED:\s*["']?true/i.test(text)) {
      issues.push({ code: "TEST_AUTHORITY_ENABLED", path: entry.path });
    }
    if (/\$\{[A-Z0-9_]+:-local-[^}]+\}/.test(text)) {
      issues.push({ code: "DEFAULT_SECRET_INCLUDED", path: entry.path });
    }
  }
  const compose = entries.find((entry) => entry.path === "compose.yaml")?.bytes.toString("utf8") ?? "";
  const postgres = composeServiceBlock(compose, "postgres", "diagnostic-bootstrap");
  const adapter = composeServiceBlock(compose, "n8n-runtime-adapter", "n8n");
  if (/\n\s+ports:/.test(postgres)) issues.push({ code: "DIRECT_DATABASE_HOST_PORT", path: "compose.yaml" });
  if (/\n\s+ports:/.test(adapter)) issues.push({ code: "INTERNAL_ADAPTER_HOST_PORT", path: "compose.yaml" });
  const publishedPorts = [...compose.matchAll(/-\s+"([^"\n]+:[^"\n]+)"/g)].map((match) => match[1]);
  if (publishedPorts.some((value) => !value.startsWith("127.0.0.1:"))) {
    issues.push({ code: "NON_LOOPBACK_PORT", path: "compose.yaml" });
  }
  if (!compose.includes("POSTGRES_PASSWORD: ${POSTGRES_PASSWORD:?generated by installer}")
      || !compose.includes("N8N_ENCRYPTION_KEY: ${N8N_ENCRYPTION_KEY:?generated by installer}")) {
    issues.push({ code: "CUSTOMER_SECRET_NOT_GENERATED", path: "compose.yaml" });
  }
  for (const required of ["release-spec.json", "OPERATOR.md", "install-local.ps1", "install-local.sh",
    "packages/n8n-operational-package/operational-package.json"]) {
    if (!paths.has(required)) issues.push({ code: "RELEASE_CONTROL_FILE_MISSING", path: required });
  }
  if (paths.has("packages/n8n-operational-package/compose.customer.yaml")) {
    issues.push({ code: "DEVELOPMENT_COMPOSITION_INCLUDED", path: "packages/n8n-operational-package/compose.customer.yaml" });
  }
  if ([...paths].some((entry) => /(^|\/)n8n(?:\.exe)?$|n8n[-_].*\.(?:tar|zip|tgz)$/i.test(entry))) {
    issues.push({ code: "N8N_BINARY_REDISTRIBUTED", path: "release" });
  }
  return { valid: issues.length === 0, issues };
}

function stableJson(value) {
  if (Array.isArray(value)) return value.map(stableJson);
  if (!value || typeof value !== "object") return value;
  return Object.fromEntries(Object.keys(value).sort().map((key) => [key, stableJson(value[key])]));
}

function jsonBytes(value) {
  return Buffer.from(`${JSON.stringify(stableJson(value), null, 2)}\n`, "utf8");
}

function names(entries, directory) {
  return entries.filter((entry) => entry.path.startsWith(`${directory}/`) && entry.path.endsWith(".sql"))
    .map((entry) => path.posix.basename(entry.path));
}

export async function buildV02Release(root, { outputDirectory = path.join(root, "dist"), write = false } = {}) {
  const payload = await collectV02ReleaseEntries(root);
  const policy = validateV02ReleaseEntries(payload);
  if (!policy.valid) throw new Error(`V0.2 release policy failed: ${JSON.stringify(policy.issues)}`);
  const spec = JSON.parse(payload.find((entry) => entry.path === "release-spec.json").bytes.toString("utf8"));
  const packageDocument = JSON.parse(payload.find((entry) => entry.path === "package.json").bytes.toString("utf8"));
  if (spec.release_version !== RELEASE_VERSION
      || Object.values(packageDocument.dependencies ?? {}).some((version) => !/^\d+\.\d+\.\d+$/.test(version))) {
    throw new Error("V0.2 release version and direct dependencies must be exact.");
  }
  if (JSON.stringify(names(payload, "migrations")) !== JSON.stringify(spec.kernel_migrations)
      || JSON.stringify(names(payload, "diagnostic-migrations")) !== JSON.stringify(spec.diagnostic_migrations)) {
    throw new Error("V0.2 release spec must pin every Kernel and Diagnostic migration in lexical order.");
  }
  const dockerfile = payload.find((entry) => entry.path === "Dockerfile").bytes.toString("utf8");
  const compose = payload.find((entry) => entry.path === "compose.yaml").bytes.toString("utf8");
  for (const image of Object.values(spec.base_images)) {
    if (!dockerfile.includes(image) && !compose.includes(image)) throw new Error(`Pinned image missing: ${image}`);
  }
  if (spec.compatible_n8n.reference_image !== spec.base_images.n8n
      || spec.compatible_n8n.redistributed !== false || spec.compatible_n8n.customer_owned !== true) {
    throw new Error("n8n must remain a pinned, upstream, customer-owned external product.");
  }
  if (spec.required_provider !== "none" || spec.managed_cloud_required !== false
      || spec.aws_deployment_included !== false) {
    throw new Error("V0.2 release must remain provider-independent, local-capable, and non-AWS.");
  }
  const payloadFiles = payload.map((entry) => ({ path: entry.path, size_bytes: entry.bytes.length,
    digest: releaseDigest(entry.bytes), mode: entry.mode.toString(8) }));
  const components = Object.fromEntries(Object.entries(spec.components).map(([name, component]) => {
    const source = payload.find((entry) => entry.path === component.entrypoint);
    if (!source) throw new Error(`Pinned V0.2 component is missing: ${component.entrypoint}`);
    return [name, { ...component, source_digest: releaseDigest(source.bytes) }];
  }));
  const embeddedManifest = {
    schema_version: "alphonse.release_manifest.v0.2",
    release_version: RELEASE_VERSION,
    kernel_protocol_version: spec.kernel_protocol_version,
    diagnostic_protocol_version: spec.diagnostic_protocol_version,
    base_images: spec.base_images,
    compatible_n8n: spec.compatible_n8n,
    components,
    payload_files: payloadFiles
  };
  const embeddedBytes = jsonBytes(embeddedManifest);
  const archive = createDeterministicTar([
    ...payload, { path: "RELEASE-MANIFEST.json", bytes: embeddedBytes, mode: 0o644 }
  ]);
  const archiveDigest = releaseDigest(archive);
  const suffix = archiveDigest.slice(7, 23);
  const archiveName = `alphonse-v${RELEASE_VERSION}-${suffix}.tar`;
  const manifest = { ...embeddedManifest, embedded_manifest_digest: releaseDigest(embeddedBytes),
    archive: { file: archiveName, size_bytes: archive.length, digest: archiveDigest,
      format: "ustar", normalized_text_line_endings: "lf", normalized_mtime: 0 } };
  const manifestBytes = jsonBytes(manifest);
  const manifestDigest = releaseDigest(manifestBytes);
  if (write) {
    await mkdir(outputDirectory, { recursive: true });
    await writeFile(path.join(outputDirectory, archiveName), archive);
    await writeFile(path.join(outputDirectory, `alphonse-v${RELEASE_VERSION}-manifest.json`), manifestBytes);
    await writeFile(path.join(outputDirectory, `alphonse-v${RELEASE_VERSION}-manifest.sha256`),
      Buffer.from(`${manifestDigest.slice(7)}  alphonse-v${RELEASE_VERSION}-manifest.json\n`, "ascii"));
  }
  return { archive, archiveName, archiveDigest, manifest, manifestBytes, manifestDigest, policy };
}
